light.css:
:root {
  --color-scheme: light;
  --bg: #ffffff;
  --surface: #f8fafc;
  --surface-2: #eef2f7;
  --text: #172033;
  --text-muted: #64748b;
  --primary: #2563eb;
  --primary-contrast: #ffffff;
  --secondary: #7c3aed;
  --success: #15803d;
  --warning: #b45309;
  --danger: #dc2626;
  --info: #0369a1;
  --border: #dbe3ee;
  --focus: #60a5fa;
  --radius: .65rem;
  --shadow: 0 8px 24px rgba(15, 23, 42, .09);
  --font-sans: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
}

