high-contrast.css:
:root {
  --color-scheme: dark;
  --bg: #000000;
  --surface: #000000;
  --surface-2: #181818;
  --text: #ffffff;
  --text-muted: #ffffff;
  --primary: #ffff00;
  --primary-contrast: #000000;
  --secondary: #00ffff;
  --success: #00ff66;
  --warning: #ffff00;
  --danger: #ff4d4d;
  --info: #00ffff;
  --border: #ffffff;
  --focus: #ffff00;
  --radius: 0;
  --shadow: none;
  --font-sans: Arial, sans-serif;
}
:focus-visible { outline: 3px solid var(--focus) !important; outline-offset: 3px; }
